// // This module increments a 10-bit counter on the rising edge of the clock when enabled, and resets it to 0 on the rising edge of the asynchronous reset.
module decrementer (
  input clk,
  input en,
  input rst,
  output reg [9:0] count);always @(posedge clk or posedge rst) begin
    if (rst)
        count <= 10'b1111111111;
    else if (en)
        count <= count - 1;
end
endmodule
